var surah032 = {
  number: 32,
  nameArabic: "as-Sajdah",
  nameEnglish: "As-Sajdah",
  meaning: "The Prostration",
  totalAyahs: 30,
  ayahs: [
    { number: 1, arabic: "الٓمٓ", transliteration: "Aliflammeem", transliterationB: "Alif-Laaam-Meeem", english: "L. M", romanUrdu: "Alif Laam Meem" },
    { number: 2, arabic: "تَنزِيلُ ٱلْكِتَٰبِ لَا رَيْبَ فِيهِ مِن رَّبِّ ٱلْعَٰلَمِينَ", transliteration: "Tanzeelu alkitabi la rayba feehi min rabbi alAAalameena", transliterationB: "Tanzeelul Kitaabi 'laaraiba feehi mir rabbil 'aalameen", english: "(This is) the Revelation of the Book in which there is no doubt,- from the Lord of the Worlds", romanUrdu: "Is kitaab ki tanzil (nuzul/revelation) bila shubha Rubb ul aalameen ki taraf se hai" },
    { number: 3, arabic: "أَمْ يَقُولُونَ ٱفْتَرَىٰهُ ۚ بَلْ هُوَ ٱلْحَقُّ مِن رَّبِّكَ لِتُنذِرَ قَوْمًۭا مَّآ أَتَىٰهُم مِّن نَّذِيرٍۢ مِّن قَبْلِكَ لَعَلَّهُمْ يَهْتَدُونَ", transliteration: "Am yaqooloona iftarahu bal huwa alhaqqu min rabbika litunthira qawman ma atahum min natheerin min qablika laAAallahum yahtadoona", transliterationB: "Am yaqooloonaf taraahu bal huwal haqqu mir rabbika litunzira qawma maaa ataahum min nazeerim min qablika la'allahum yahtadoon", english: "Or do they say, \"He has forged it\"? Nay, it is the Truth from thy Lord, that thou mayest admonish a people to whom no warner has come before thee: in order that they may receive guidance", romanUrdu: "Kya yeh log kehte hain ke is shaks ne isey khud ghadh liya hai? Nahin, balke yeh haqq hai tere Rubb ki taraf se taa-ke tu mutanabbeh (warn) karey ek aisi qaum ko jiske paas tujhse pehle koi mutanabbeh (warn) karne nahin aaya. Shayad ke woh hidayat paa jayein" },
    { number: 4, arabic: "ٱللَّهُ ٱلَّذِى خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا فِى سِتَّةِ أَيَّامٍۢ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ ۖ مَا لَكُم مِّن دُونِهِۦ مِن وَلِىٍّۢ وَلَا شَفِيعٍ ۚ أَفَلَا تَتَذَكَّرُونَ", transliteration: "Allahu allathee khalaqa alssamawati waalarda wama baynahuma fee sittati ayyamin thumma istawa AAala alAAarshi ma lakum min doonihi min waliyyin wala shafeeAAin afala tatathakkaroona", transliterationB: "Allaahul lazee khalaqas samaawaati wal arda wa maa bainahumaa fee sittati ayyaam;Thummas tawaa 'alal 'arsh; maa lakum min doonihee minw-wwaliyyinw-wala shafee'; afala tatazakkaroon", english: "It is Allah Who has created the heavens and the earth, and all between them, in six Days, and is firmly established on the Throne (of Authority): ye have none, besides Him, to protect or intercede (for you): will ye not then receive admonition", romanUrdu: "Woh Allah hi hai jisne aasmaano aur zameen ko aur un saari cheezon ko jo inke darmiyan hain chey (six) dino mein paida kiya aur iske baad arsh par jalwa farma hua. Uske siwa na tumhara koi haami o madadgar hai aur na koi uske aagey sifarish karne wala. Phir kya tum hosh mein na aaogey" },
    { number: 5, arabic: "يُدَبِّرُ ٱلْأَمْرَ مِنَ ٱلسَّمَآءِ إِلَى ٱلْأَرْضِ ثُمَّ يَعْرُجُ إِلَيْهِ فِى يَوْمٍۢ كَانَ مِقْدَارُهُۥٓ أَلْفَ سَنَةٍۢ مِّمَّا تَعُدُّونَ", transliteration: "Yudabbiru alamra mina alssamai ila alardi thumma yaAAruju ilayhi fee yawmin kana miqdaruhu alfa sanatin mimma taAAuddoona", transliterationB: "Yudabbirul amra minas samaaa'i ilal ardi Thumma ya'ruju ilai Thumma ya'ruju ilaihi fee yawmin kaana miqdaaruhoooo alfa sanatim mimmaa ta'uddoon", english: "He rules (all) affairs from the heavens to the earth: in the end will (all affairs) go up to Him, on a Day, the space whereof will be (as) a thousand years of your reckoning", romanUrdu: "Woh aasmaan se zameen tak duniya ke maamlaat ki tadbeer (planning) karta hai aur is tadbeer ki rudad (record) upar uske huzur jaati hai ek aisey din mein jiski miqdaar tumhare shumar se ek hazar saal hai" },
    { number: 6, arabic: "ذَٰلِكَ عَٰلِمُ ٱلْغَيْبِ وَٱلشَّهَٰدَةِ ٱلْعَزِيزُ ٱلرَّحِيمُ", transliteration: "Thalika AAalimu alghaybi waalshshahadati alAAazeezu alrraheemu", transliterationB: "Zaalika 'aalimul ghaybi wa shahaadatil 'azeezur raheem", english: "Such is He, the Knower of all things, hidden and open, the Exalted (in power), the Merciful", romanUrdu: "Wahi hai har posheeda (chupi hui) aur zaahir ka janne wala. Zabardast, aur raheem" },
    { number: 7, arabic: "ٱلَّذِىٓ أَحْسَنَ كُلَّ شَىْءٍ خَلَقَهُۥ ۖ وَبَدَأَ خَلْقَ ٱلْإِنسَٰنِ مِن طِينٍۢ", transliteration: "Allathee ahsana kulla shayin khalaqahu wabadaa khalqa alinsani min teenin", transliterationB: "Allazee ahsana kulla shai in khalaqa; wa bada a khalqal insaani min teen", english: "He Who has made everything which He has created most good: He began the creation of man with (nothing more than) clay", romanUrdu: "Jo cheez bhi usney banayi khoob hi (acchi tarah) banayi. Usne Insaan ki takhleeq ki ibtida gaarey (mitti /clay) se ki" },
    { number: 8, arabic: "ثُمَّ جَعَلَ نَسْلَهُۥ مِن سُلَٰلَةٍۢ مِّن مَّآءٍۢ مَّهِينٍۢ", transliteration: "Thumma jaAAala naslahu min sulalatin min main maheenin", transliterationB: "Thumma ja'ala naslahoo min sulaalatim mim maaa'immaheen", english: "And made his progeny from a quintessence of the nature of a fluid despised", romanUrdu: "Phir uski nasal ek aisi saat se chalayi jo hakeer pani (fluid despised) ki tarah ka hai" },
    { number: 9, arabic: "ثُمَّ سَوَّىٰهُ وَنَفَخَ فِيهِ مِن رُّوحِهِۦ ۖ وَجَعَلَ لَكُمُ ٱلسَّمْعَ وَٱلْأَبْصَٰرَ وَٱلْأَفْـِٔدَةَ ۚ قَلِيلًۭا مَّا تَشْكُرُونَ", transliteration: "Thumma sawwahu wanafakha feehi min roohihi wajaAAala lakumu alssamAAa waalabsara waalafidata qaleelan ma tashkuroona", transliterationB: "Thumma sawwaahu wa nafakha feehi mir roohihih; wa ja'ala lakumus sam'a wal-absaara wal-af'idah; taqaleelam maa tashkuroon", english: "But He fashioned him in due proportion, and breathed into him something of His spirit. And He gave you (the faculties of) hearing and sight and feeling (and understanding): little thanks do ye give", romanUrdu: "Phir usko nik-suk se durust kiya aur uske andar apni rooh phoonk di. Aur tumko kaan diye, aankhein di aur dil diye. Tum log kam hi shukar guazar hotey ho" },
    { number: 10, arabic: "وَقَالُوٓا۟ أَءِذَا ضَلَلْنَا فِى ٱلْأَرْضِ أَءِنَّا لَفِى خَلْقٍۢ جَدِيدٍۭ ۚ بَلْ هُم بِلِقَآءِ رَبِّهِمْ كَٰفِرُونَ", transliteration: "Waqaloo aitha dalalna fee alardi ainna lafee khalqin jadeedin bal hum biliqai rabbihim kafiroona", transliterationB: "Wa qaalooo 'a-izaa dalalnaa fil ardi 'a-innaa lafee khalqin jadeed; bal hum biliqaaa'i rabbihim kaafirroon", english: "And they say: \"What! when we lie, hidden and lost, in the earth, shall we indeed be in a Creation renewed? Nay, they deny the Meeting with their Lord", romanUrdu: "Aur yeh log kehte hain: “jab hum mitti mein ral-mil chuke honge to kya hum phir naye sirey se paida kiye jayenge?” Asal baat yeh hai ke yeh apne Rubb ki mulaqaat ke munkir hain" },
    { number: 11, arabic: "۞ قُلْ يَتَوَفَّىٰكُم مَّلَكُ ٱلْمَوْتِ ٱلَّذِى وُكِّلَ بِكُمْ ثُمَّ إِلَىٰ رَبِّكُمْ تُرْجَعُونَ", transliteration: "Qul yatawaffakum malaku almawti allathee wukkila bikum thumma ila rabbikum turjaAAoona", transliterationB: "Qul yatawaffaakum malakul mawtil lazee wukkila bikum Thumma ilaa rabbikum turja'oon", english: "Say: \"The Angel of Death, put in charge of you, will (duly) take your souls: then shall ye be brought back to your Lord", romanUrdu: "Insey kaho “Maut ka woh farishta jo tumpar muqarrar kiya gaya hai tumko poora ka poora apne qabze mein le lega aur phir tum apne Rubb ki taraf palta laye jaoge”" },
    { number: 12, arabic: "وَلَوْ تَرَىٰٓ إِذِ ٱلْمُجْرِمُونَ نَاكِسُوا۟ رُءُوسِهِمْ عِندَ رَبِّهِمْ رَبَّنَآ أَبْصَرْنَا وَسَمِعْنَا فَٱرْجِعْنَا نَعْمَلْ صَٰلِحًا إِنَّا مُوقِنُونَ", transliteration: "Walaw tara ithi almujrimoona nakisoo ruoosihim AAinda rabbihim rabbana absarna wasamiAAna faarjiAAna naAAmal salihan inna mooqinoona", transliterationB: "Wa law taraaa izil mujrimoona naakisoo ru'oosihim 'inda rabbihim rabbanaaa absarnaa wa sami'naa farji'naa na'mal saalihan innaa mooqinoon", english: "If only thou couldst see when the guilty ones will bend low their heads before their Lord, (saying:) \"Our Lord! We have seen and we have heard: Now then send us back (to the world): we will work righteousness: for we do indeed (now) believe", romanUrdu: "Kaash tum dekho woh waqt jab yeh mujrim sar jhukaye apne Rubb ke huzur khade hongey. (Us waqt yeh keh rahe hongey) “ Aey hamare Rubb, humne khoob dekh liya aur sun liya , ab humein wapas bhej de taa-ke hum neik amal karein. Humein ab yaqeen aa gaya hai.”" },
    { number: 13, arabic: "وَلَوْ شِئْنَا لَءَاتَيْنَا كُلَّ نَفْسٍ هُدَىٰهَا وَلَٰكِنْ حَقَّ ٱلْقَوْلُ مِنِّى لَأَمْلَأَنَّ جَهَنَّمَ مِنَ ٱلْجِنَّةِ وَٱلنَّاسِ أَجْمَعِينَ", transliteration: "Walaw shina laatayna kulla nafsin hudaha walakin haqqa alqawlu minnee laamlaanna jahannama mina aljinnati waalnnasi ajmaAAeena", transliterationB: "Wa law shi'naa la-aatainaa kulla nafsin hudaahaa wa laakin haqqal qawlu minnee la amla'anna jahannama minal jinnati wannaasi ajma'een", english: "If We had so willed, We could certainly have brought every soul its true guidance: but the Word from Me will come true, \"I will fill Hell with Jinns and men all together", romanUrdu: "(Jawab mein irshad hoga) “Agar hum chahte to pehle hi har nafs ko iski hidayat de detay, magar meri woh baat poori ho gayi jo maine kahi thi ke main jahannum ko Jinno aur Insano sab se bhar dunga" },
    { number: 14, arabic: "فَذُوقُوا۟ بِمَا نَسِيتُمْ لِقَآءَ يَوْمِكُمْ هَٰذَآ إِنَّا نَسِينَٰكُمْ ۖ وَذُوقُوا۟ عَذَابَ ٱلْخُلْدِ بِمَا كُنتُمْ تَعْمَلُونَ", transliteration: "Fathooqoo bima naseetum liqaa yawmikum hatha inna naseenakum wathooqoo AAathaba alkhuldi bima kuntum taAAmaloona", transliterationB: "Fazooqoo bimaa naseetum liqaaa'a yawminkum haaza innaa naseenaakum wa zooqoo 'azaabal khuldi bimaa kuntum ta'maloon", english: "Taste ye then - for ye forgot the Meeting of this Day of yours, and We too will forget you - taste ye the Penalty of Eternity for your (evil) deeds", romanUrdu: "Pas ab chakkho maza apni is harakat ka ke tumne is din ki mulaqat ko faramosh kardiya. Humne bhi ab tumhein faramosh kardiya hai. Chakkho hameshgi ke azaab ka maza apne kartooton ki padash mein”" },
    { number: 15, arabic: "إِنَّمَا يُؤْمِنُ بِـَٔايَٰتِنَا ٱلَّذِينَ إِذَا ذُكِّرُوا۟ بِهَا خَرُّوا۟ سُجَّدًۭا وَسَبَّحُوا۟ بِحَمْدِ رَبِّهِمْ وَهُمْ لَا يَسْتَكْبِرُونَ ۩", transliteration: "Innama yuminu biayatina allatheena itha thukkiroo biha kharroo sujjadan wasabbahoo bihamdi rabbihim wahum la yastakbiroona", transliterationB: "Innamaa yu'minu bi aayaatinal lazeena izaa zukkiroo bihaa kharroo sujjadanw wa sabbahoo bihamdi rabbihim wa hum laa yastakbiroon", english: "Only those believe in Our Signs, who, when they are recited to them, fall down in prostration, and celebrate the praises of their Lord, nor are they (ever) puffed up with pride", romanUrdu: "Hamari aayat par to woh log iman laatey hain jinhein yeh aayat suna kar jab naseehat ki jaati hai to sajde mein gir padte hain aur apne Rubb ki hamd ke saath uski tasbeeh karte hain aur takabbur nahin karte" },
    { number: 16, arabic: "تَتَجَافَىٰ جُنُوبُهُمْ عَنِ ٱلْمَضَاجِعِ يَدْعُونَ رَبَّهُمْ خَوْفًۭا وَطَمَعًۭا وَمِمَّا رَزَقْنَٰهُمْ يُنفِقُونَ", transliteration: "Tatajafa junoobuhum AAani almadajiAAi yadAAoona rabbahum khawfan watamaAAan wamimma razaqnahum yunfiqoona", transliterationB: "Tatajaafaa junoobuhum 'anil madaaji'i yad'oona rabbahum khawfanw wa tama'anw wa mimmaa razaqnaahum yunfiqoon", english: "Their limbs do forsake their beds of sleep, the while they call on their Lord, in Fear and Hope: and they spend (in charity) out of the sustenance which We have bestowed on them", romanUrdu: "Unki peethein (backs) bistaron se alag rehti hain, apne Rubb ko khauf aur tamaa (umeed) ke saath pukarte hain. Aur jo kuch rizq humne unhein diya hai usmein se kharch karte hain" },
    { number: 17, arabic: "فَلَا تَعْلَمُ نَفْسٌۭ مَّآ أُخْفِىَ لَهُم مِّن قُرَّةِ أَعْيُنٍۢ جَزَآءًۢ بِمَا كَانُوا۟ يَعْمَلُونَ", transliteration: "Fala taAAlamu nafsun ma okhfiya lahum min qurrati aAAyunin jazaan bima kanoo yaAAmaloona", transliterationB: "Falaa ta'lamu nafsum maaa ukhfiya lahum min qurrati a'yunin jazaaa'am bimaa kaanoo ya'maloon", english: "Now no person knows what delights of the eye are kept hidden (in reserve) for them - as a reward for their (good) deeds", romanUrdu: "Phir jaisa kuch aankhon ki thandak ka saamaan unke aamaal ki jaza mein unke liye chupa kar rakkha gaya hai uski kisi mutanaffis (person/soul) ko khabar nahin hai" },
    { number: 18, arabic: "أَفَمَن كَانَ مُؤْمِنًۭا كَمَن كَانَ فَاسِقًۭا ۚ لَّا يَسْتَوُۥنَ", transliteration: "Afaman kana muminan kaman kana fasiqan la yastawoona", transliterationB: "Afaman kaana mu'minan kaman kaana faasiqaa; laa yasta woon", english: "Is then the man who believes no better than the man who is rebellious and wicked? Not equal are they", romanUrdu: "Bhala kahin yeh ho sakta hai ke jo shaks momin ho woh us shaks ki tarah ho jaye jo faasiq (nafarman/evil doer) ho? Yeh dono barabar nahin ho saktey" },
    { number: 19, arabic: "أَمَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ فَلَهُمْ جَنَّٰتُ ٱلْمَأْوَىٰ نُزُلًۢا بِمَا كَانُوا۟ يَعْمَلُونَ", transliteration: "Amma allatheena amanoo waAAamiloo alssalihati falahum jannatu almawa nuzulan bima kanoo yaAAmaloona", transliterationB: "Ammal lazeena aamanoo wa 'amilus saalihaati falahum jannaatul maawa nuzulam bimaa kaanoo ya'maloon", english: "For those who believe and do righteous deeds are Gardens as hospitable homes, for their (good) deeds", romanUrdu: "Jo log iman laye hain aur jinhon ne neik amal kiye hain unke liye to jannaton ki qayam-gahein (hospitable homes) hain. Ziyafat ke taur par unke aamal ke badle mein" },
    { number: 20, arabic: "وَأَمَّا ٱلَّذِينَ فَسَقُوا۟ فَمَأْوَىٰهُمُ ٱلنَّارُ ۖ كُلَّمَآ أَرَادُوٓا۟ أَن يَخْرُجُوا۟ مِنْهَآ أُعِيدُوا۟ فِيهَا وَقِيلَ لَهُمْ ذُوقُوا۟ عَذَابَ ٱلنَّارِ ٱلَّذِى كُنتُم بِهِۦ تُكَذِّبُونَ", transliteration: "Waamma allatheena fasaqoo famawahumu alnnaru kullama aradoo an yakhrujoo minha oAAeedoo feeha waqeela lahum thooqoo AAathaba alnnari allathee kuntum bihi tukaththiboona", transliterationB: "Wa ammal lazeena fasaqoo famaawaahumn Naaru kullamaaa araadooo any yakhrujoo minhaaa u'eedoo feehaa wa qeela lahum zooqoo 'zaaaban Naaril lazee kuntum bihee tukazziboon", english: "As to those who are rebellious and wicked, their abode will be the Fire: every time they wish to get away therefrom, they will be forced thereinto, and it will be said to them: \"Taste ye the Penalty of the Fire, the which ye were wont to reject as false", romanUrdu: "Aur jinhon ne fisq (na-farmani) ikhtiyar kiya hai unka thikana dozakh hai.Jab kabhi woh ussey nikalna chahenge usi mein dhakail diye jayenge aur unsey kaha jayega ke chakkho ab usi aag ke azaab ka maza jisko tum jhutlaya karte thay" },
    { number: 21, arabic: "وَلَنُذِيقَنَّهُم مِّنَ ٱلْعَذَابِ ٱلْأَدْنَىٰ دُونَ ٱلْعَذَابِ ٱلْأَكْبَرِ لَعَلَّهُمْ يَرْجِعُونَ", transliteration: "Walanutheeqannahum mina alAAathabi aladna doona alAAathabi alakbari laAAallahum yarjiAAoona", transliterationB: "Wa lanuzeeqan nahum minal 'azaabil ladnaa doonal 'azaabil akbari la'allahum yarji'oon", english: "And indeed We will make them taste of the Penalty of this (life) prior to the supreme Penalty, in order that they may (repent and) return", romanUrdu: "Us baday azaab se pehle hum isi duniya mein (kisi na kisi chote) azaab ka maza inhein chakhate rahenge. Shayad ke yeh (apne baagiyana [transgression] rawish se) baaz aa jayein" },
    { number: 22, arabic: "وَمَنْ أَظْلَمُ مِمَّن ذُكِّرَ بِـَٔايَٰتِ رَبِّهِۦ ثُمَّ أَعْرَضَ عَنْهَآ ۚ إِنَّا مِنَ ٱلْمُجْرِمِينَ مُنتَقِمُونَ", transliteration: "Waman athlamu mimman thukkira biayati rabbihi thumma aAArada AAanha inna mina almujrimeena muntaqimoona", transliterationB: "Wa man azlamu mimman zukkira bi aayaati rabbihee summa a'rada 'anhaa; innaa minal mujrimeena muntaqimmon", english: "And who does more wrong than one to whom are recited the Signs of his Lord, and who then turns away therefrom? Verily from those who transgress We shall exact (due) Retribution", romanUrdu: "Aur ussey bada zaalim kaun hoga jisey uske Rubb ki aayat ke zariye se naseehat ki jaye aur phir woh inse mooh pher ley.Aisey mujreemo se to hum inteqam lekar rahenge" },
    { number: 23, arabic: "وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ فَلَا تَكُن فِى مِرْيَةٍۢ مِّن لِّقَآئِهِۦ ۖ وَجَعَلْنَٰهُ هُدًۭى لِّبَنِىٓ إِسْرَٰٓءِيلَ", transliteration: "Walaqad atayna moosa alkitaba fala takun fee miryatin min liqaihi wajaAAalnahu hudan libanee israeela", transliterationB: "Wa laqad aayainaa Moosal Kitaaba falaa takun fee miryatim mil liqaaa'ihee wa ja'alnaahu hudal li Baneee Israaa'eel", english: "We did indeed aforetime give the Book to Moses: be not then in doubt of its reaching (thee): and We made it a guide to the Children of Israel", romanUrdu: "Issey pehle hum Moosa ko kitaab de chuke hain. Lihaza usi cheez ke milne par tumhein koi shakk na hona chahiye. Us kitab ko humne bani Israel ke liye hidayat banaya tha" },
    { number: 24, arabic: "وَجَعَلْنَا مِنْهُمْ أَئِمَّةًۭ يَهْدُونَ بِأَمْرِنَا لَمَّا صَبَرُوا۟ ۖ وَكَانُوا۟ بِـَٔايَٰتِنَا يُوقِنُونَ", transliteration: "WajaAAalna minhum aimmatan yahdoona biamrina lamma sabaroo wakanoo biayatina yooqinoona", transliterationB: "Wa ja'alnaa minhum a'immatany yahdoona bi amrinaa lammaa sabaroo wa kaanoo bi aayaatinaa yooqinoon", english: "And We appointed, from among them, leaders, giving guidance under Our command, so long as they persevered with patience and continued to have faith in Our Signs", romanUrdu: "Aur jab unhon ne sabr kiya aur hamari aayaat par yaqeen latey rahey to unke andar humne aise peshwa paida kiye jo hamare hukum se rehnumayi (hidayat/guidance) karte thay" },
    { number: 25, arabic: "إِنَّ رَبَّكَ هُوَ يَفْصِلُ بَيْنَهُمْ يَوْمَ ٱلْقِيَٰمَةِ فِيمَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ", transliteration: "Inna rabbaka huwa yafsilu baynahum yawma alqiyamati feema kanoo feehi yakhtalifoona", transliterationB: "Inna rabbaka huwa yafsilu bainahum yawmal qiyaamati feemaa kaanoo feehi yakhtalifoon", english: "Verily thy Lord will judge between them on the Day of Judgment, in the matters wherein they differ (among themselves)", romanUrdu: "Yaqeenan tera Rubb hi qayamat ke roz un baaton ka faisla karega jinmein (bani Israel) baaham(aapas mein) ikhtilaf karte rahey hain" },
    { number: 26, arabic: "أَوَلَمْ يَهْدِ لَهُمْ كَمْ أَهْلَكْنَا مِن قَبْلِهِم مِّنَ ٱلْقُرُونِ يَمْشُونَ فِى مَسَٰكِنِهِمْ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍ ۖ أَفَلَا يَسْمَعُونَ", transliteration: "Awalam yahdi lahum kam ahlakna min qablihim mina alqurooni yamshoona fee masakinihim inna fee thalika laayatin afala yasmaAAoona", transliterationB: "Awalam yahdi lahum kam ahlaknaa min qablihim minal qurooni yamshoona fee zaalika la aayaatin afalaa yasma'oon", english: "Does it not teach them a lesson, how many generations We destroyed before them, in whose dwellings they (now) go to and fro? Verily in that are Signs: Do they not then listen", romanUrdu: "Aur kya in logon ko (in tareekhi (historical) waqiyat mein) koi hidayat nahin mili ke unse pehle kitni qaumon ko hum halaak kar chuke hain jinke rehne ki jaghon mein aaj yeh chalte phirte hain? Ismein badi nishaniyan hain. Kya yeh sunte nahin hain" },
    { number: 27, arabic: "أَوَلَمْ يَرَوْا۟ أَنَّا نَسُوقُ ٱلْمَآءَ إِلَى ٱلْأَرْضِ ٱلْجُرُزِ فَنُخْرِجُ بِهِۦ زَرْعًۭا تَأْكُلُ مِنْهُ أَنْعَٰمُهُمْ وَأَنفُسُهُمْ ۖ أَفَلَا يُبْصِرُونَ", transliteration: "Awalam yaraw anna nasooqu almaa ila alardi aljuruzi fanukhriju bihi zarAAan takulu minhu anAAamuhum waanfusuhum afala yubsiroona", transliterationB: "Awalam yaraw annaa nasooqul maaa'a ilal lardil juruzi fanukhriju bihee zar'an taakulu minhu an'aamuhum wa anfusuhum afalaa yubsiroon", english: "And do they not see that We do drive rain to parched soil (bare of herbage), and produce therewith crops, providing food for their cattle and themselves? Have they not the vision", romanUrdu: "Aur kya in logon ne yeh manzar kabhi nahin dekha ke hum ek bay-aab o gayah (banjar) zameen ki taraf pani baha latey hain, aur phir usi zameen se woh fasal ugati hai jissey unke jaanwaron ko bhi chara milta hai aur yeh khud bhi khate hain? To kya inhein kuch nahin soojhta" },
    { number: 28, arabic: "وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلْفَتْحُ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Wayaqooloona mata hatha alfathu in kuntum sadiqeena", transliterationB: "Wa yaqooloona mataa haazal fat hu in kuntum saadiqeen", english: "They say: \"When will this decision be, if ye are telling the truth", romanUrdu: "Yeh log kehte hain ke “yeh faisla kab hoga agar tum sachhey ho?”" },
    { number: 29, arabic: "قُلْ يَوْمَ ٱلْفَتْحِ لَا يَنفَعُ ٱلَّذِينَ كَفَرُوٓا۟ إِيمَٰنُهُمْ وَلَا هُمْ يُنظَرُونَ", transliteration: "Qul yawma alfathi la yanfaAAu allatheena kafaroo eemanuhum wala hum yuntharoona", transliterationB: "Qul yawmal fat hi laa yanfa'ul lazeena kafarooo eemaanuhum wa laa hum yunzaroon", english: "Say: \"On the Day of Decision, no profit will it be to Unbelievers if they (then) believe! nor will they be granted a respite", romanUrdu: "Insey kaho “faisle ke din iman laana un logon ke liye kuch bhi nafeh (faidemand) na hoga jinhon ne kufr kiya hai aur phir unko koi mohlat na milegi.”" },
    { number: 30, arabic: "فَأَعْرِضْ عَنْهُمْ وَٱنتَظِرْ إِنَّهُم مُّنتَظِرُونَ", transliteration: "FaaAArid AAanhum waintathir innahum muntathiroona", transliterationB: "Fa a'rid 'anhum wantazir innahum muntazirron", english: "So turn away from them, and wait: they too are waiting", romanUrdu: "Accha, inhein inke haal par chodh do aur intezar karo, yeh bhi muntazir (intezar kar rahe) hain" }
  ]
};
